/**
 * Extract bank batch reference codes from a transaction description.
 * Based on REVA's bank-statement-mb-batch-reconcile.mjs logic.
 *
 * Batch refs are 14–20 digit numbers starting with "25",
 * or INHOUSE patterns like "25011016424 145673-INHOUSE".
 */

/** Score a batch ref candidate — higher = more likely correct. */
function scoreBulkRefCandidate(ref: string): number {
  if (ref.endsWith('-INHOUSE')) return 20;
  if (/^25\d{12,16}$/.test(ref)) return 100;
  if (ref.startsWith('25')) return 50;
  return 0;
}

/** Join fragmented INHOUSE ref groups. */
function joinInhouseRefGroups(groups: string[]): string {
  if (!groups.length) return '';
  const joinedAll = groups.join('');
  if (joinedAll.length >= 11 && joinedAll.length <= 22 && /^25/.test(joinedAll)) return joinedAll;
  const last = groups[groups.length - 1];
  if (last.length >= 14 && /^25/.test(last)) return last;
  const joined = groups.slice(-2).join('');
  if (joined.length >= 11 && joined.length <= 22 && /^25/.test(joined)) return joined;
  const best = [...groups].reverse().find(g => g.length >= 11 && /^25/.test(g));
  return best || joinedAll || joined;
}

/**
 * Extract bulk ref candidates from a transaction description string.
 * Returns sorted array (best candidate first).
 */
export function extractBulkRefsFromDescription(desc: string | undefined | null): string[] {
  const s = String(desc ?? '');
  if (!s.trim()) return [];
  const refs = new Set<string>();

  // Pattern 1: INHOUSE suffix — e.g. "25011016424 145673-INHOUSE"
  for (const m of s.matchAll(/-\s*INHOUSE/gi)) {
    const end = m.index;
    let pos = end - 1;
    while (pos >= 0) {
      const ch = s[pos];
      if (ch === '.') break;
      if (!/[\d\s]/.test(ch)) break;
      pos -= 1;
    }
    const groups = s
      .slice(pos + 1, end)
      .trim()
      .split(/\s+/)
      .filter(g => /^\d+$/.test(g));
    const joined = joinInhouseRefGroups(groups);
    if (joined.length >= 11 && joined.length <= 22) {
      refs.add(joined);
      refs.add(`${joined}-INHOUSE`);
    }
  }

  // Pattern 2: 14–20 consecutive digits starting with "25"
  const norm = s.replace(/\s/g, '').toUpperCase();
  for (const m of norm.matchAll(/\d{14,20}/g)) {
    const digits = m[0];
    if (digits.startsWith('25') && digits.length >= 14) refs.add(digits);
  }

  // Pattern 3: Any 25-prefixed sequence 11–22 digits
  const digitsOnly = s.replace(/\D/g, '');
  for (const m of digitsOnly.matchAll(/25\d{6,19}/g)) {
    const digits = m[0];
    if (digits.length >= 11 && digits.length <= 22) refs.add(digits);
  }

  return [...refs].sort((a, b) => scoreBulkRefCandidate(b) - scoreBulkRefCandidate(a));
}

/**
 * Check if a row's description has batch references that match
 * any of the batch payment files loaded from parsed batch data.
 */
export function findMatchingBatchRefs(
  detectedRefs: string[],
  parsedBatchRefs: string[],
): string[] {
  if (!detectedRefs.length || !parsedBatchRefs.length) return [];

  const matched: string[] = [];
  for (const ref of detectedRefs) {
    const normalized = ref.replace(/-INHOUSE$/i, '');
    if (parsedBatchRefs.some(br => br === normalized || br === ref)) {
      matched.push(ref);
    }
  }
  return matched;
}

/**
 * Normalize a batch ref for comparison.
 */
export function normalizeBulkRef(ref: string): string {
  return ref.replace(/-INHOUSE$/i, '').replace(/\s/g, '');
}
