import { apiClient, unwrap, type BffResponse } from '../api';
import type {
  BankStatementImportRequest,
  BankStatementImportRow,
  BankStatementDryRunResult,
  BankStatementImportExecute,
  BankStatementImportResult,
  CustomerMatchResult,
  BatchDetailLine,
} from './bankStatementImportModels';

const BASE = '/accounting/bank-statements';

export const bankStatementImportService = {
  matchCustomers: async (rows: BankStatementImportRow[], bankStatementFile?: string) => {
    const res = await apiClient.post<BffResponse<CustomerMatchResult>>(`${BASE}/match-customers`, {
      rows,
      bankStatementFile,
    });
    return unwrap(res);
  },

  dryRun: async (dto: BankStatementImportRequest) => {
    const res = await apiClient.post<BffResponse<BankStatementDryRunResult>>(`${BASE}/dry-run`, dto);
    return unwrap(res);
  },

  executeImport: async (dto: BankStatementImportExecute) => {
    const res = await apiClient.post<BffResponse<BankStatementImportResult>>(`${BASE}/import`, dto);
    return unwrap(res);
  },
};

/** Parse batch payment files to extract detail lines keyed by batch ref. */
export function parseBatchPaymentFiles(
  files: File[],
): Promise<Map<string, BatchDetailLine[]>> {
  const result = new Map<string, BatchDetailLine[]>();
  return Promise.all(
    files.map(async (file) => {
      const lines = await parseBatchFile(file);
      for (const line of lines) {
        const ref = line.batchRef || file.name;
        if (!result.has(ref)) result.set(ref, []);
        result.get(ref)!.push(line);
      }
    }),
  ).then(() => result);
}

async function parseBatchFile(file: File): Promise<(BatchDetailLine & { batchRef?: string })[]> {
  const buffer = await file.arrayBuffer();
  const text = new TextDecoder('utf-8').decode(buffer);
  const lines = text.split('\n').filter(Boolean);
  if (lines.length < 2) return [];

  const header = lines[0].toLowerCase();
  const dataLines = lines.slice(1);

  // Detect columns
  const colIdx = (keywords: string[]) => {
    const parts = header.split(/[,;\t]/).map(h => h.trim().toLowerCase());
    for (const kw of keywords) {
      const idx = parts.findIndex(p => p.includes(kw));
      if (idx >= 0) return idx;
    }
    return -1;
  };

  const nameIdx = colIdx(['thụ hưởng', 'thu huong', 'beneficiary', 'tên', 'name', 'ncc', 'kh']);
  const amountIdx = colIdx(['số tiền', 'amount', 'tiền', 'giá trị', 'gia tri']);
  const accountIdx = colIdx(['tài khoản', 'account', 'stk', 'số tk']);
  const bankIdx = colIdx(['ngân hàng', 'bank', 'nh']);
  const ftIdx = colIdx(['ft', 'số ft', 'mã gd', 'transaction', 'ref']);
  const refIdx = colIdx(['mã lô', 'batch', 'bulk', 'ref', 'ma lo']);

  const batchRefs: (BatchDetailLine & { batchRef?: string })[] = [];

  for (let i = 0; i < dataLines.length; i++) {
    const parts = dataLines[i].split(/[,;\t]/).map(p => p.trim());
    if (parts.length < 2) continue;

    const amountStr = amountIdx >= 0 ? parts[amountIdx] : '';
    const amount = parseFloat(amountStr.replace(/[,.]/g, m => m === ',' ? '' : '.')) || 0;

    batchRefs.push({
      lineIndex: i,
      beneficiaryName: nameIdx >= 0 ? parts[nameIdx] : '',
      accountNumber: accountIdx >= 0 ? parts[accountIdx] : undefined,
      bankName: bankIdx >= 0 ? parts[bankIdx] : undefined,
      amount,
      ftNumber: ftIdx >= 0 ? parts[ftIdx] : undefined,
      batchRef: refIdx >= 0 ? parts[refIdx] : undefined,
    });
  }

  return batchRefs;
}

/** Số dòng xử lý mỗi batch khi gọi import (default 50). */
export const IMPORT_BATCH_SIZE = 50;
